            compare_field(
                "results_sha256",
                &recorded.results_sha256,
                &Some(actual.results_sha256),
                &mut differences,
            );
            compare_field(
                "final_state_sha256",
                &recorded.final_state_sha256,
                &Some(actual.final_state_sha256),
                &mut differences,
            );
