                for pin in &supplied_pins {
                    let expected = manifest::ResolvedValue::from(&pin.value);
                    compare_field(
                        &format!("executions[{}].resolved_theta.{}", execution.k, pin.name),
                        &execution.resolved_theta.get(&pin.name),
                        &Some(&expected),
                        &mut differences,
                    );
