   110	impl RunManifest {
   111	    pub fn new(
   112	        kind: ManifestKind,
   113	        seed: u64,
   114	        ticks: u32,
   115	        population_source: PopulationSource,
   116	        population_sha256: String,
   117	    ) -> Self {
   118	        let mut schema_versions = BTreeMap::new();
   119	        schema_versions.insert(
   120	            "backend_identity".to_owned(),
   121	            BACKEND_IDENTITY_SCHEMA_VERSION,
   122	        );
   123	        schema_versions.insert("manifest".to_owned(), MANIFEST_SCHEMA_VERSION);
   124	        let mut component_versions = BTreeMap::new();
   125	        component_versions.insert(
   126	            "sembla-cli".to_owned(),
   127	            env!("CARGO_PKG_VERSION").to_owned(),
   128	        );
   129	        component_versions.insert("sembla-ir".to_owned(), sembla_ir::VERSION.to_owned());
   130	        component_versions.insert(
   131	            "sembla-runtime".to_owned(),
   132	            sembla_runtime::VERSION.to_owned(),
   133	        );
   134	        Self {
   135	            backend_identity: Some(BackendIdentity::cpu_oracle()),
   136	            component_versions,
   137	            determinism_level: DETERMINISM_LEVEL.to_owned(),
   138	            enabled_flags: Vec::new(),
   139	            executions: Vec::new(),
   140	            final_state_hash_algorithm: HASH_ALGORITHM.to_owned(),
   141	            final_state_sha256: None,
   142	            ir_hash: None,
   143	            ir_hash_algorithm: HASH_ALGORITHM.to_owned(),
   144	            manifest_kind: kind,
   145	            model: None,
   146	            population_hash_algorithm: HASH_ALGORITHM.to_owned(),
   147	            population_sha256,
   148	            population_source,
   149	            resolved_theta: BTreeMap::new(),
   150	            results_hash_algorithm: HASH_ALGORITHM.to_owned(),
   151	            results_sha256: None,
   152	            schema_versions,
   153	            seed,
   154	            dt: None,
   155	            ticks,
   156	        }
   157	    }
   158	}
   159	
   160	pub fn resolved_theta(params: &sembla_runtime::eval::ParamEnv) -> BTreeMap<String, ResolvedValue> {
   161	    params
   162	        .values()
   163	        .map(|(name, value)| (name.to_owned(), ResolvedValue::from(value)))
   164	        .collect()
   165	}
   166	
   167	pub fn canonical_ir_hash(model: &sembla_ir::ValidatedModel) -> Result<String, String> {
   168	    let canonical = sembla_ir::to_canonical_json(model.model())
   169	        .map_err(|error| format!("canonical IR serialization failed: {error}"))?;
   170	    Ok(hex(&Sha256::digest(canonical.as_bytes())))
   171	}
   172	
   173	pub fn population_identity(spec: &str) -> Result<(PopulationSource, String), String> {
   174	    if let Ok(value) = spec.parse::<u64>() {
   175	        let canonical = format!("{value}\n");
   176	        return Ok((
   177	            PopulationSource::Numeric(value),
   178	            hex(&Sha256::digest(canonical.as_bytes())),
   179	        ));
   180	    }
   181	    let path = Path::new(spec);
   182	    let basename = path
   183	        .file_name()
   184	        .and_then(|name| name.to_str())
   185	        .ok_or_else(|| format!("population path '{spec}' has no UTF-8 basename"))?;
   186	    let bytes = std::fs::read(path).map_err(|error| format!("{spec}: {error}"))?;
   187	    Ok((
   188	        PopulationSource::File(basename.to_owned()),
   189	        hex(&Sha256::digest(bytes)),
   190	    ))
   191	}
   192	
   193	pub fn sidecar_path(output: &str) -> PathBuf {
   194	    PathBuf::from(format!("{output}.manifest.json"))
   195	}
   196	
   197	pub fn write(path: &Path, manifest: &RunManifest) -> Result<(), String> {
   198	    let bytes = to_canonical_json(manifest)?;
   199	    std::fs::write(path, bytes.as_bytes()).map_err(|error| format!("{}: {error}", path.display()))
   200	}
   201	
   202	pub fn read(path: &Path) -> Result<RunManifest, String> {
   203	    let source =
   204	        std::fs::read_to_string(path).map_err(|error| format!("{}: {error}", path.display()))?;
   205	    let value: serde_json::Value =
   206	        serde_json::from_str(&source).map_err(|error| format!("{}: {error}", path.display()))?;
   207	    validate_schema_versions(&value)?;
   208	    validate_backend_identity_tuple(&value)?;
   209	    // Deserialize from the original bytes rather than through `Value`: the
   210	    // latter can round an already-parsed f64 during `from_value`, which would
   211	    // break exact replay of sampled sweep parameters.
   212	    let manifest: RunManifest =
   213	        serde_json::from_str(&source).map_err(|error| format!("{}: {error}", path.display()))?;
   214	    validate_algorithms(&manifest)?;
   215	    Ok(manifest)
   216	}
   217	
   218	pub fn to_canonical_json(manifest: &RunManifest) -> Result<String, String> {
   219	    let mut normalized = manifest.clone();
   220	    normalized.enabled_flags.sort();
   221	    normalized.enabled_flags.dedup();
   222	    let value = serde_json::to_value(normalized).map_err(|error| error.to_string())?;
   223	    let mut json = serde_json::to_string(&sort_json(value)).map_err(|error| error.to_string())?;
   224	    json.push('\n');
   225	    Ok(json)
   226	}
   227	
   228	fn sort_json(value: serde_json::Value) -> serde_json::Value {
   229	    match value {
   230	        serde_json::Value::Object(object) => {
   231	            let mut entries = object.into_iter().collect::<Vec<_>>();
   232	            entries.sort_by(|left, right| left.0.cmp(&right.0));
   233	            let object = entries
   234	                .into_iter()
   235	                .map(|(key, value)| (key, sort_json(value)))
   236	                .collect();
   237	            serde_json::Value::Object(object)
   238	        }
   239	        serde_json::Value::Array(values) => {
   240	            serde_json::Value::Array(values.into_iter().map(sort_json).collect())
   241	        }
   242	        other => other,
   243	    }
   244	}
   245	
   246	fn validate_schema_versions(value: &serde_json::Value) -> Result<(), String> {
   247	    let versions = value
   248	        .get("schema_versions")
   249	        .and_then(serde_json::Value::as_object)
   250	        .ok_or_else(|| "manifest schema_versions must be an object".to_owned())?;
   251	    for (concern, expected) in [
   252	        ("manifest", MANIFEST_SCHEMA_VERSION),
   253	        ("backend_identity", BACKEND_IDENTITY_SCHEMA_VERSION),
   254	    ] {
   255	        let actual = versions
   256	            .get(concern)
   257	            .and_then(serde_json::Value::as_u64)
   258	            .ok_or_else(|| format!("manifest schema_versions.{concern} is missing or invalid"))?;
   259	        if actual != u64::from(expected) {
   260	            return Err(format!(
   261	                "unknown schema_versions major for {concern}: {actual} (supported: {expected})"
   262	            ));
   263	        }
   264	    }
   265	    for concern in versions.keys() {
   266	        if concern != "manifest" && concern != "backend_identity" {
   267	            return Err(format!(
   268	                "unknown schema_versions concern '{concern}' and major {}",
   269	                versions[concern]
   270	            ));
   271	        }
   272	    }
   273	    Ok(())
   274	}
   275	
   276	fn validate_backend_identity_tuple(value: &serde_json::Value) -> Result<(), String> {
   277	    let Some(identity) = value.get("backend_identity") else {
   278	        return Ok(());
   279	    };
   280	    if identity.is_null() {
   281	        return Ok(());
   282	    }
   283	    let object = identity.as_object().ok_or_else(|| {
   284	        "backend_identity tuple must be all-present or all-absent and must be an object".to_owned()
   285	    })?;
   286	    let missing = ["backend", "precision", "fell_back"]
   287	        .into_iter()
   288	        .filter(|field| !object.contains_key(*field))
   289	        .collect::<Vec<_>>();
   290	    if !missing.is_empty() {
   291	        return Err(format!(
   292	            "backend_identity tuple must be all-present or all-absent; missing {}",
   293	            missing.join(", ")
   294	        ));
   295	    }
   296	    Ok(())
   297	}
   298	
   299	fn validate_algorithms(manifest: &RunManifest) -> Result<(), String> {
   300	    for (field, value) in [
   301	        ("ir_hash_algorithm", manifest.ir_hash_algorithm.as_str()),
   302	        (
   303	            "population_hash_algorithm",
