   634	fn remove_previous_sweep_outputs(directory: &Path) -> Result<(), String> {
   635	    for entry in
   636	        std::fs::read_dir(directory).map_err(|error| format!("{}: {error}", directory.display()))?
   637	    {
   638	        let path = entry
   639	            .map_err(|error| format!("{}: {error}", directory.display()))?
   640	            .path();
   641	        let name = path
   642	            .file_name()
   643	            .and_then(|name| name.to_str())
   644	            .unwrap_or("");
   645	        if name == "manifest.csv"
   646	            || name == "run-manifest.json"
   647	            || name == "summary.csv"
   648	            || (name.starts_with("draw_") && name.ends_with(".csv"))
   649	        {
   650	            std::fs::remove_file(&path).map_err(|error| format!("{}: {error}", path.display()))?;
   651	        }
   652	    }
   653	    Ok(())
   654	}
