   299	fn validate_algorithms(manifest: &RunManifest) -> Result<(), String> {
   300	    for (field, value) in [
   301	        ("ir_hash_algorithm", manifest.ir_hash_algorithm.as_str()),
   302	        (
   303	            "population_hash_algorithm",
   304	            manifest.population_hash_algorithm.as_str(),
   305	        ),
   306	        (
   307	            "results_hash_algorithm",
   308	            manifest.results_hash_algorithm.as_str(),
   309	        ),
   310	        (
   311	            "final_state_hash_algorithm",
   312	            manifest.final_state_hash_algorithm.as_str(),
   313	        ),
   314	    ] {
   315	        if value != HASH_ALGORITHM {
   316	            return Err(format!(
   317	                "unsupported {field} '{value}' (supported: '{HASH_ALGORITHM}')"
   318	            ));
   319	        }
   320	    }
   321	    Ok(())
   322	}
