   526	fn sweep_file_result(path: &str, options: SweepOptions) -> Result<(), String> {
   527	    let model = read_validated(path)?;
   528	    let (population_source, population_sha256) =
   529	        manifest::population_identity(&options.population)?;
   530	    let mut run_manifest = manifest::RunManifest::new(
   531	        manifest::ManifestKind::Sweep,
   532	        options.seed,
   533	        options.ticks,
   534	        population_source,
   535	        population_sha256,
   536	    );
   537	    run_manifest.model = Some(model.model().name.clone());
   538	    run_manifest.dt = Some(model.model().dt);
   539	    run_manifest.ir_hash = Some(manifest::canonical_ir_hash(&model)?);
   540	    if optional_sir_box_name(&model)?.is_none() {
   541	        return Err(
   542	            "sweep summary currently requires exactly one SIR person/employer box; use sembla run for generic models"
   543	                .to_owned(),
   544	        );
   545	    }
   546	    let pinned = match options.params.as_deref() {
   547	        Some(params_path) => read_param_overrides(&model, params_path)?,
   548	        None => Vec::new(),
   549	    };
   550	    let population = options.population.parse::<usize>().ok();
   551	    let population_file = if population.is_none() {
   552	        Some(SyntheticPopulation::read(&options.population).map_err(|error| error.to_string())?)
   553	    } else {
   554	        None
   555	    };
   556	    let out = Path::new(&options.out);
   557	    std::fs::create_dir_all(out).map_err(|error| format!("{}: {error}", out.display()))?;
   558	    remove_previous_sweep_outputs(out)?;
   559	
   560	    let mut manifest = String::from("# parameter_status");
   561	    for declaration in &model.model().params {
   562	        let status = if pinned.iter().any(|pin| pin.name == declaration.name) {
   563	            "pinned"
   564	        } else if declaration.prior.is_some() {
   565	            "sampled"
   566	        } else {
   567	            "default"
   568	        };
   569	        manifest.push_str(&format!(",{}={status}", declaration.name));
   570	    }
   571	    manifest.push_str("\nk");
   572	    for declaration in &model.model().params {
   573	        manifest.push(',');
   574	        manifest.push_str(&declaration.name);
   575	    }
   576	    manifest.push('\n');
   577	
   578	    let mut all_series = Vec::with_capacity(options.draws as usize);
   579	    // Deliberately sequential: declaration order within each k, then k order.
   580	    for draw in 0..options.draws {
   581	        let params = sample_parameters_for_draw(&model, options.seed, draw, &pinned)
   582	            .map_err(|error| format!("draw {draw}: {error}"))?;
   583	        manifest.push_str(&draw.to_string());
   584	        for (_, value) in params.values() {
   585	            manifest.push(',');
   586	            manifest.push_str(&param_value_csv(value));
   587	        }
   588	        manifest.push('\n');
   589	
   590	        let initial = match (&population, &population_file) {
   591	            (Some(row_count), None) => initialize_population(&model, *row_count),
   592	            (None, Some(population)) => initializers_from_population(&model, population)?,
   593	            _ => return Err("invalid sweep population source".to_owned()),
   594	        };
   595	        let mut state =
   596	            StateStore::new(&model, initial).map_err(|error| format!("{path}: {error}"))?;
   597	        // The simulation seed is intentionally identical across k: this is
   598	        // common random numbers, so only theta varies between unpinned draws.
   599	        let (csv, series) =
   600	            run_sir_results_csv(&model, &mut state, &params, options.seed, options.ticks)?;
   601	        let hashes = execution_hashes(&csv, &state);
   602	        run_manifest.executions.push(manifest::ManifestExecution {
   603	            k: draw,
   604	            scenario: None,
   605	            model: None,
   606	            ir_hash: None,
   607	            dt: None,
   608	            resolved_theta: manifest::resolved_theta(&params),
   609	            results_sha256: hashes.results_sha256,
   610	            final_state_sha256: hashes.final_state_sha256,
   611	        });
   612	        let draw_path = out.join(format!("draw_{draw}.csv"));
   613	        std::fs::write(&draw_path, csv.as_bytes())
   614	            .map_err(|error| format!("{}: {error}", draw_path.display()))?;
   615	        all_series.push(series);
   616	    }
   617	
   618	    let summary = summary_csv(&all_series, options.ticks);
   619	    let manifest_path = out.join("manifest.csv");
   620	    let summary_path = out.join("summary.csv");
   621	    std::fs::write(&manifest_path, manifest.as_bytes())
   622	        .map_err(|error| format!("{}: {error}", manifest_path.display()))?;
   623	    std::fs::write(&summary_path, summary.as_bytes())
   624	        .map_err(|error| format!("{}: {error}", summary_path.display()))?;
   625	    manifest::write(&out.join("run-manifest.json"), &run_manifest)?;
   626	    println!(
   627	        "manifest_sha256={} summary_sha256={}",
   628	        hex(&Sha256::digest(manifest.as_bytes())),
   629	        hex(&Sha256::digest(summary.as_bytes()))
   630	    );
   631	    Ok(())
   632	}
