  1221	        manifest::ManifestKind::Sweep => {
  1222	            let executions = match options.draw {
  1223	                Some(draw) => vec![recorded
  1224	                    .executions
  1225	                    .iter()
  1226	                    .find(|execution| execution.k == draw)
  1227	                    .ok_or_else(|| format!("manifest has no sweep execution with k={draw}"))?],
  1228	                None => recorded.executions.iter().collect::<Vec<_>>(),
  1229	            };
  1230	            if executions.is_empty() {
  1231	                return Err("sweep manifest contains no executions".to_owned());
