  1477	    for (index, (name, value)) in params.values().enumerate() {
  1478	        if index != 0 {
  1479	            object.push(',');
  1480	        }
  1481	        object.push_str(&serde_json::to_string(name).map_err(|error| error.to_string())?);
  1482	        object.push(':');
  1483	        match value {
