  1485	                object.push_str(&serde_json::to_string(value).map_err(|error| error.to_string())?)
  1486	            }
  1487	            ParamValue::Int { value } => object.push_str(&value.to_string()),
  1488	        }
  1489	    }
  1490	    object.push('}');
  1491	    Ok(object)
  1492	}
