   218	pub fn to_canonical_json(manifest: &RunManifest) -> Result<String, String> {
   219	    let mut normalized = manifest.clone();
   220	    normalized.enabled_flags.sort();
   221	    normalized.enabled_flags.dedup();
   222	    let value = serde_json::to_value(normalized).map_err(|error| error.to_string())?;
   223	    let mut json = serde_json::to_string(&sort_json(value)).map_err(|error| error.to_string())?;
   224	    json.push('\n');
   225	    Ok(json)
   226	}
