   246	fn validate_schema_versions(value: &serde_json::Value) -> Result<(), String> {
   247	    let versions = value
   248	        .get("schema_versions")
   249	        .and_then(serde_json::Value::as_object)
   250	        .ok_or_else(|| "manifest schema_versions must be an object".to_owned())?;
   251	    for (concern, expected) in [
   252	        ("manifest", MANIFEST_SCHEMA_VERSION),
   253	        ("backend_identity", BACKEND_IDENTITY_SCHEMA_VERSION),
   254	    ] {
   255	        let actual = versions
   256	            .get(concern)
   257	            .and_then(serde_json::Value::as_u64)
   258	            .ok_or_else(|| format!("manifest schema_versions.{concern} is missing or invalid"))?;
   259	        if actual != u64::from(expected) {
   260	            return Err(format!(
   261	                "unknown schema_versions major for {concern}: {actual} (supported: {expected})"
   262	            ));
   263	        }
   264	    }
   265	    for concern in versions.keys() {
   266	        if concern != "manifest" && concern != "backend_identity" {
   267	            return Err(format!(
   268	                "unknown schema_versions concern '{concern}' and major {}",
   269	                versions[concern]
   270	            ));
   271	        }
   272	    }
   273	    Ok(())
   274	}
