   276	fn validate_backend_identity_tuple(value: &serde_json::Value) -> Result<(), String> {
   277	    let Some(identity) = value.get("backend_identity") else {
   278	        return Ok(());
   279	    };
   280	    if identity.is_null() {
   281	        return Ok(());
   282	    }
   283	    let object = identity.as_object().ok_or_else(|| {
   284	        "backend_identity tuple must be all-present or all-absent and must be an object".to_owned()
   285	    })?;
   286	    let missing = ["backend", "precision", "fell_back"]
   287	        .into_iter()
   288	        .filter(|field| !object.contains_key(*field))
   289	        .collect::<Vec<_>>();
   290	    if !missing.is_empty() {
   291	        return Err(format!(
   292	            "backend_identity tuple must be all-present or all-absent; missing {}",
   293	            missing.join(", ")
   294	        ));
   295	    }
   296	    Ok(())
   297	}
